				</el-form-item>
				<el-form-item class="upload" v-else-if="ruleForm.tupian" label="图片" prop="tupian" >
					<img v-if="ruleForm.tupian.substring(0,4)=='http'&&ruleForm.tupian.split(',w').length>1" class="upload-img" style="margin-right:20px;" v-bind:key="index" :src="ruleForm.tupian" width="100" height="100" @click="imgPreView(ruleForm.tupian)">
					<img v-else-if="ruleForm.tupian.substring(0,4)=='http'" class="upload-img" style="margin-right:20px;" v-bind:key="index" :src="ruleForm.tupian.split(',')[0]" width="100" height="100" @click="imgPreView(ruleForm.tupian.split(',')[0])">
					<img v-else class="upload-img" style="margin-right:20px;" v-bind:key="index" v-for="(item,index) in ruleForm.tupian.split(',')" :src="$base.url+item" width="100" height="100" @click="imgPreView($base.url+item)">
				</el-form-item>
				<el-form-item class="input" v-if="type!='info'"  label="实验室位置" prop="shiyanshiweizhi" >
					<el-input v-model="ruleForm.shiyanshiweizhi" placeholder="实验室位置" clearable  :readonly="ro.shiyanshiweizhi"></el-input>
				</el-form-item>
				<el-form-item v-else class="input" label="实验室位置" prop="shiyanshiweizhi" >
					<el-input v-model="ruleForm.shiyanshiweizhi" placeholder="实验室位置" readonly></el-input>
				</el-form-item>
				<el-form-item class="input" v-if="type!='info'"  label="容量" prop="rongliang" >
					<el-input v-model="ruleForm.rongliang" placeholder="容量" clearable  :readonly="ro.rongliang"></el-input>
				</el-form-item>
				<el-form-item v-else class="input" label="容量" prop="rongliang" >
					<el-input v-model="ruleForm.rongliang" placeholder="容量" readonly></el-input>
				</el-form-item>
				<el-form-item class="input" v-if="type!='info'"  label="可预约次数" prop="reduciblenum" >
					<el-input v-model.number="ruleForm.reduciblenum" placeholder="可预约次数" clearable  :readonly="ro.reduciblenum"></el-input>
				</el-form-item>
				<el-form-item v-else class="input" label="可预约次数" prop="reduciblenum" >
					<el-input v-model="ruleForm.reduciblenum" placeholder="可预约次数" readonly></el-input>
				</el-form-item>
				<el-form-item class="input" v-if="type!='info'"  label="开放时间" prop="kaifangshijian" >
					<el-input v-model="ruleForm.kaifangshijian" placeholder="开放时间" clearable  :readonly="ro.kaifangshijian"></el-input>
				</el-form-item>
				<el-form-item v-else class="input" label="开放时间" prop="kaifangshijian" >
					<el-input v-model="ruleForm.kaifangshijian" placeholder="开放时间" readonly></el-input>
				</el-form-item>
			</template>
			<el-form-item class="textarea" v-if="type!='info'" label="仪器配置" prop="yiqipeizhi" >
				<el-input
					style="min-width: 200px; max-width: 600px;"
					type="textarea"
					:rows="8"
					placeholder="仪器配置"
					v-model="ruleForm.yiqipeizhi" >
				</el-input>
			</el-form-item>
			<el-form-item v-else-if="ruleForm.yiqipeizhi" label="仪器配置" prop="yiqipeizhi"  class="textBox">
				<span class="text">{{ruleForm.yiqipeizhi}}</span>
			</el-form-item>
			<el-form-item class="textarea" v-if="type!='info'" label="预约规则" prop="yuyueguize" >
				<el-input
					style="min-width: 200px; max-width: 600px;"
					type="textarea"
					:rows="8"
					placeholder="预约规则"
					v-model="ruleForm.yuyueguize" >
				</el-input>
			</el-form-item>
			<el-form-item v-else-if="ruleForm.yuyueguize" label="预约规则" prop="yuyueguize"  class="textBox">
				<span class="text">{{ruleForm.yuyueguize}}</span>
			</el-form-item>
			<el-form-item v-if="type!='info'" class="editorBox" label="环境介绍" prop="huanjingjieshao" >
				<editor 
					style="min-width: 200px; max-width: 600px;"
					v-model="ruleForm.huanjingjieshao" 
					class="editor"
					myQuillEditor="huanjingjieshao"
					action="file/upload">
				</editor>
			</el-form-item>
			<el-form-item v-else-if="ruleForm.huanjingjieshao" label="环境介绍" prop="huanjingjieshao"  class="textBox">
				<span class="text ql-snow ql-editor" v-html="ruleForm.huanjingjieshao"></span>
			</el-form-item>
			<el-form-item class="btn">
				<el-button class="btn3"  v-if="type!='info'" type="success" @click="onSubmit">
					<span class="icon iconfont icon-queren15"></span>
					提交
				</el-button>
				<el-button class="btn4" v-if="type!='info'" type="success" @click="back()">
					<span class="icon iconfont icon-guanbi2"></span>
					取消
				</el-button>
				<el-button class="btn5" v-if="type=='info'" type="success" @click="back()">
					<span class="icon iconfont icon-fanhui13"></span>
					返回
				</el-button>
			</el-form-item>
		</el-form>
    

	</div>
</template>
<script>
	import { 
		isNumber,
		isIntNumer,
	} from "@/utils/validate";
	export default {
		data() {
			var validateNumber = (rule, value, callback) => {
				if(!value){
					callback();
				} else if (!isNumber(value)) {
					callback(new Error("请输入数字"));
				} else {
					callback();
				}
			};
			var validateIntNumber = (rule, value, callback) => {
				if(!value){
					callback();
				} else if (!isIntNumer(value)) {
					callback(new Error("请输入整数"));
				} else {
					callback();
				}
			};
			return {
				id: '',
				type: '',
			
			
				ro:{
					bianhao : false,
					shiyanshimingcheng : false,
					shiyanshileixing : false,
					yuanxi : false,
					tupian : false,
					shiyanshiweizhi : false,
					yiqipeizhi : false,
					rongliang : false,
					reduciblenum : false,
					kaifangshijian : false,
					yuyueguize : false,
					huanjingjieshao : false,
					discussnum : false,
					totalscore : false,
					storeupnum : false,
				},
			
				ruleForm: {
					bianhao: '',
					shiyanshimingcheng: '',
					shiyanshileixing: '',
					yuanxi: '',
					tupian: '',
					shiyanshiweizhi: '',
					yiqipeizhi: '',
					rongliang: '',
					reduciblenum: Number('1'),
					kaifangshijian: '',
					yuyueguize: '',
					huanjingjieshao: '',
					discussnum: Number('0'),
					totalscore: '0',
					storeupnum: Number('0'),
				},
				yuanxiOptions: [],

				rules: {
					bianhao: [
						{ required: true, message: '编号不能为空', trigger: 'blur' },
					],
					shiyanshimingcheng: [
						{ required: true, message: '实验室名称不能为空', trigger: 'blur' },
					],
					shiyanshileixing: [
						{ required: true, message: '实验室类型不能为空', trigger: 'blur' },
					],
					yuanxi: [
					],
					tupian: [
					],
					shiyanshiweizhi: [
					],
					yiqipeizhi: [
					],
					rongliang: [
					],
					reduciblenum: [
						{ validator: validateIntNumber, trigger: 'blur' },
					],
					kaifangshijian: [
					],
					yuyueguize: [
					],
					huanjingjieshao: [
					],
					discussnum: [
						{ validator: validateIntNumber, trigger: 'blur' },
					],
					totalscore: [
						{ validator: validateNumber, trigger: 'blur' },
					],
					storeupnum: [
						{ validator: validateIntNumber, trigger: 'blur' },
					],
				},
			};
		},
		props: ["parent"],
		computed: {
			sessionForm() {
				return JSON.parse(this.$storage.getObj('userForm'))
			},
			sessionTable() {
				return this.$storage.get('sessionTable')
			},



		},
		components: {
		},
		created() {
		},
		methods: {
			imgPreView(url){
				this.$parent.imgPreView(url)
			},
			// 下载
			download(file){
				window.open(`${file}`)
			},
			// 初始化
			init(id,type ) {
				if (id) {
					this.id = id;
					this.type = type;
				}
				if(this.type=='info'||this.type=='else'||this.type=='msg'){
					this.info(id);
				}else if(this.type=='logistics'){
					for(let x in this.ro) {
						this.ro[x] = true
					}
					this.logistics=false;
					this.info(id);
				}else if(this.type=='cross'){
					var obj = this.$storage.getObj('crossObj');
					for (var o in obj){
						if(o=='bianhao'){
							this.ruleForm.bianhao = obj[o];
							this.ro.bianhao = true;
							continue;
						}
						if(o=='shiyanshimingcheng'){
							this.ruleForm.shiyanshimingcheng = obj[o];
							this.ro.shiyanshimingcheng = true;
							continue;
						}
						if(o=='shiyanshileixing'){
							this.ruleForm.shiyanshileixing = obj[o];
							this.ro.shiyanshileixing = true;
							continue;
						}
						if(o=='yuanxi'){
							this.ruleForm.yuanxi = obj[o];
							this.ro.yuanxi = true;
							continue;
						}
						if(o=='tupian'){
							this.ruleForm.tupian = obj[o];
							this.ro.tupian = true;
							continue;
						}
						if(o=='shiyanshiweizhi'){
							this.ruleForm.shiyanshiweizhi = obj[o];
							this.ro.shiyanshiweizhi = true;
							continue;
						}
						if(o=='yiqipeizhi'){
							this.ruleForm.yiqipeizhi = obj[o];
							this.ro.yiqipeizhi = true;
							continue;
						}
						if(o=='rongliang'){
							this.ruleForm.rongliang = obj[o];
							this.ro.rongliang = true;
							continue;
						}
						if(o=='reduciblenum'){
							this.ruleForm.reduciblenum = obj[o];
							this.ro.reduciblenum = true;
							continue;
						}
						if(o=='kaifangshijian'){
							this.ruleForm.kaifangshijian = obj[o];
							this.ro.kaifangshijian = true;
							continue;
						}
						if(o=='yuyueguize'){
							this.ruleForm.yuyueguize = obj[o];
							this.ro.yuyueguize = true;
							continue;
						}
						if(o=='huanjingjieshao'){
							this.ruleForm.huanjingjieshao = obj[o];
							this.ro.huanjingjieshao = true;
							continue;
						}
						if(o=='discussnum'){
							this.ruleForm.discussnum = obj[o];
							this.ro.discussnum = true;
							continue;
						}
						if(o=='totalscore'){
							this.ruleForm.totalscore = obj[o];
							this.ro.totalscore = true;
							continue;
						}
						if(o=='storeupnum'){
							this.ruleForm.storeupnum = obj[o];
							this.ro.storeupnum = true;
							continue;
						}
					}
					this.ruleForm.reduciblenum = Number('1'); 				}

				// 获取用户信息
				this.$http({
					url: `${this.sessionTable}/session`,
					method: "get"
				}).then(({ data }) => {
					if (data && data.code === 0) {
						var json = data.data;
						if(this.sessionTable!="users") {
							this.ro.reduciblenum = true;
						}
					} else {
						this.$message.error(data.msg);
					}
				});
				this.$http({
					url: `option/yuanxi/yuanxi`,
					method: "get",
				}).then(({ data }) => {
					if (data && data.code === 0) {
						this.yuanxiOptions = data.data;
					} else {
						this.$message.error(data.msg);
					}
				});
			
			},
			// 多级联动参数

			async info(id) {
				await this.$http({
					url: `shiyanshi/info/${id}`,
					method: "get"
				}).then(({ data }) => {
					if (data && data.code === 0) {
						this.ruleForm = data.data;
						//解决前台上传图片后台不显示的问题
						let reg=new RegExp('../../../upload','g')//g代表全部
						this.ruleForm.huanjingjieshao = this.ruleForm.huanjingjieshao.replace(reg,'../../../shiyanshi88x6c3gh/upload');
					} else {
						this.$message.error(data.msg);
					}
				});
			},

			// 提交
			async onSubmit() {
					if(this.ruleForm.tupian!=null) {
						this.ruleForm.tupian = this.ruleForm.tupian.replace(new RegExp(this.$base.url,"g"),"");
					}
					var objcross = this.$storage.getObj('crossObj');
					if(!this.ruleForm.id) {
						delete this.ruleForm.userid
					}
					await this.$refs["ruleForm"].validate(async valid => {
						if (valid) {
							if(this.type=='cross'){
								var statusColumnName = this.$storage.get('statusColumnName');
								var statusColumnValue = this.$storage.get('statusColumnValue');
								if(statusColumnName!='') {
									var obj = this.$storage.getObj('crossObj');
									if(statusColumnName && !statusColumnName.startsWith("[")) {
										for (var o in obj){
											if(o==statusColumnName){
												obj[o] = statusColumnValue;
											}
										}
										var table = this.$storage.get('crossTable');
										await this.$http({
											url: `${table}/update`,
											method: "post",
											data: obj
										}).then(({ data }) => {});
									}
								}
							}
							await this.$http({
								url: `shiyanshi/${!this.ruleForm.id ? "save" : "update"}`,
								method: "post",
								data: this.ruleForm
							}).then(async ({ data }) => {
								if (data && data.code === 0) {
									this.$message({
										message: "操作成功",
										type: "success",
										duration: 1500,
										onClose: () => {
											this.parent.showFlag = true;
											this.parent.addOrUpdateFlag = false;
											this.parent.shiyanshiCrossAddOrUpdateFlag = false;
											this.parent.search();
										}
									});
								} else {
									this.$message.error(data.msg);
								}
							});
						}
					});
			},
			// 获取uuid
			getUUID () {
				return new Date().getTime();
			},
			// 返回
			back() {
				this.parent.showFlag = true;
				this.parent.addOrUpdateFlag = false;
				this.parent.shiyanshiCrossAddOrUpdateFlag = false;
			},
			tupianUploadChange(fileUrls) {
				this.ruleForm.tupian = fileUrls;
			},
		}
	};
</script>
