				<el-form-item class="input" v-if="type!='info'"  label="实验室位置" prop="shiyanshiweizhi" >
					<el-input v-model="ruleForm.shiyanshiweizhi" placeholder="实验室位置" clearable  :readonly="ro.shiyanshiweizhi"></el-input>
