					<img v-else-if="ruleForm.xianchangzhaopian.substring(0,4)=='http'" class="upload-img" style="margin-right:20px;" v-bind:key="index" :src="ruleForm.xianchangzhaopian.split(',')[0]" width="100" height="100" @click="imgPreView(ruleForm.tupian.split(',')[0])">
					<img v-else class="upload-img" style="margin-right:20px;" v-bind:key="index" v-for="(item,index) in ruleForm.xianchangzhaopian.split(',')" :src="$base.url+item" width="100" height="100" @click="imgPreView($base.url+item)">
