</template>
<script>
	export default {
		data() {
			return {
				id: '',
				type: '',
			
			
				ro:{
					bianhao : false,
					shiyanshimingcheng : false,
					shiyanshileixing : false,
					yuanxi : false,
					shiyanshiweizhi : false,
					yiqipeizhi : false,
					xianchangzhaopian : false,
					xunchaxiangmu : false,
					xunchashijian : false,
					xunchajilu : false,
				},
			
				ruleForm: {
					bianhao: '',
					shiyanshimingcheng: '',
					shiyanshileixing: '',
					yuanxi: '',
					shiyanshiweizhi: '',
					yiqipeizhi: '',
					xianchangzhaopian: '',
					xunchaxiangmu: '',
					xunchashijian: '',
					xunchajilu: '',
				},
				yuanxiOptions: [],

				rules: {
					bianhao: [
						{ required: true, message: '编号不能为空', trigger: 'blur' },
					],
					shiyanshimingcheng: [
						{ required: true, message: '实验室名称不能为空', trigger: 'blur' },
					],
					shiyanshileixing: [
						{ required: true, message: '实验室类型不能为空', trigger: 'blur' },
					],
					yuanxi: [
					],
					shiyanshiweizhi: [
					],
					yiqipeizhi: [
					],
					xianchangzhaopian: [
					],
					xunchaxiangmu: [
					],
					xunchashijian: [
					],
					xunchajilu: [
					],
				},
			};
		},
		props: ["parent"],
		computed: {
			sessionForm() {
				return JSON.parse(this.$storage.getObj('userForm'))
			},
			sessionTable() {
				return this.$storage.get('sessionTable')
			},



		},
		components: {
		},
		created() {
			this.ruleForm.xunchashijian = this.getCurDateTime()
		},
		methods: {
			imgPreView(url){
				this.$parent.imgPreView(url)
			},
			// 下载
			download(file){
				window.open(`${file}`)
			},
			// 初始化
			init(id,type ) {
				if (id) {
					this.id = id;
					this.type = type;
				}
				if(this.type=='info'||this.type=='else'||this.type=='msg'){
					this.info(id);
				}else if(this.type=='logistics'){
					for(let x in this.ro) {
						this.ro[x] = true
					}
					this.logistics=false;
					this.info(id);
				}else if(this.type=='cross'){
					var obj = this.$storage.getObj('crossObj');
					for (var o in obj){
						if(o=='bianhao'){
							this.ruleForm.bianhao = obj[o];
							this.ro.bianhao = true;
							continue;
						}
						if(o=='shiyanshimingcheng'){
							this.ruleForm.shiyanshimingcheng = obj[o];
							this.ro.shiyanshimingcheng = true;
							continue;
						}
						if(o=='shiyanshileixing'){
							this.ruleForm.shiyanshileixing = obj[o];
							this.ro.shiyanshileixing = true;
							continue;
						}
						if(o=='yuanxi'){
							this.ruleForm.yuanxi = obj[o];
							this.ro.yuanxi = true;
							continue;
						}
						if(o=='shiyanshiweizhi'){
							this.ruleForm.shiyanshiweizhi = obj[o];
							this.ro.shiyanshiweizhi = true;
							continue;
						}
						if(o=='yiqipeizhi'){
							this.ruleForm.yiqipeizhi = obj[o];
							this.ro.yiqipeizhi = true;
							continue;
						}
						if(o=='xianchangzhaopian'){
							this.ruleForm.xianchangzhaopian = obj[o];
							this.ro.xianchangzhaopian = true;
							continue;
						}
						if(o=='xunchaxiangmu'){
							this.ruleForm.xunchaxiangmu = obj[o];
							this.ro.xunchaxiangmu = true;
							continue;
						}
						if(o=='xunchashijian'){
							this.ruleForm.xunchashijian = obj[o];
							this.ro.xunchashijian = true;
							continue;
						}
						if(o=='xunchajilu'){
							this.ruleForm.xunchajilu = obj[o];
							this.ro.xunchajilu = true;
							continue;
						}
					}
				}

				// 获取用户信息
				this.$http({
					url: `${this.sessionTable}/session`,
					method: "get"
				}).then(({ data }) => {
					if (data && data.code === 0) {
						var json = data.data;
					} else {
						this.$message.error(data.msg);
					}
				});
				this.$http({
					url: `option/yuanxi/yuanxi`,
					method: "get",
				}).then(({ data }) => {
					if (data && data.code === 0) {
						this.yuanxiOptions = data.data;
					} else {
						this.$message.error(data.msg);
					}
				});
			
			},
			// 多级联动参数

			async info(id) {
				await this.$http({
					url: `xunchajilu/info/${id}`,
					method: "get"
				}).then(({ data }) => {
					if (data && data.code === 0) {
						this.ruleForm = data.data;
						//解决前台上传图片后台不显示的问题
						let reg=new RegExp('../../../upload','g')//g代表全部
						this.ruleForm.xunchajilu = this.ruleForm.xunchajilu.replace(reg,'../../../shiyanshi88x6c3gh/upload');
					} else {
						this.$message.error(data.msg);
					}
				});
			},

			// 提交
			async onSubmit() {
					if(this.ruleForm.xianchangzhaopian!=null) {
						this.ruleForm.xianchangzhaopian = this.ruleForm.xianchangzhaopian.replace(new RegExp(this.$base.url,"g"),"");
					}
					var objcross = this.$storage.getObj('crossObj');
					if(!this.ruleForm.id) {
						delete this.ruleForm.userid
					}
					await this.$refs["ruleForm"].validate(async valid => {
						if (valid) {
							if(this.type=='cross'){
								var statusColumnName = this.$storage.get('statusColumnName');
								var statusColumnValue = this.$storage.get('statusColumnValue');
								if(statusColumnName!='') {
									var obj = this.$storage.getObj('crossObj');
									if(statusColumnName && !statusColumnName.startsWith("[")) {
										for (var o in obj){
											if(o==statusColumnName){
												obj[o] = statusColumnValue;
											}
										}
										var table = this.$storage.get('crossTable');
										await this.$http({
											url: `${table}/update`,
											method: "post",
											data: obj
										}).then(({ data }) => {});
									}
								}
							}
							await this.$http({
								url: `xunchajilu/${!this.ruleForm.id ? "save" : "update"}`,
								method: "post",
								data: this.ruleForm
							}).then(async ({ data }) => {
								if (data && data.code === 0) {
									this.$message({
										message: "操作成功",
										type: "success",
										duration: 1500,
										onClose: () => {
											this.parent.showFlag = true;
											this.parent.addOrUpdateFlag = false;
											this.parent.xunchajiluCrossAddOrUpdateFlag = false;
											this.parent.search();
										}
									});
								} else {
									this.$message.error(data.msg);
								}
							});
						}
					});
			},
			// 获取uuid
			getUUID () {
				return new Date().getTime();
			},
			// 返回
			back() {
				this.parent.showFlag = true;
				this.parent.addOrUpdateFlag = false;
				this.parent.xunchajiluCrossAddOrUpdateFlag = false;
			},
			xianchangzhaopianUploadChange(fileUrls) {
				this.ruleForm.xianchangzhaopian = fileUrls;
			},
		}
	};
</script>
