	<div class="addEdit-block">
		<el-form
			class="add-update-preview"
			ref="ruleForm"
			:model="ruleForm"
			:rules="rules"
			label-width="180px"
		>
			<template >
				<el-form-item class="input" v-if="type!='info'"  label="知识标题" prop="zhishibiaoti" >
					<el-input v-model="ruleForm.zhishibiaoti" placeholder="知识标题" clearable  :readonly="ro.zhishibiaoti"></el-input>
				</el-form-item>
				<el-form-item v-else class="input" label="知识标题" prop="zhishibiaoti" >
					<el-input v-model="ruleForm.zhishibiaoti" placeholder="知识标题" readonly></el-input>
				</el-form-item>
				<el-form-item class="select" v-if="type!='info'"  label="知识类型" prop="zhishileixing" >
					<el-select :disabled="ro.zhishileixing" v-model="ruleForm.zhishileixing" placeholder="请选择知识类型"  filterable>
						<el-option
							v-for="(item,index) in zhishileixingOptions"
							v-bind:key="index"
							:label="item"
							:value="item">
						</el-option>
					</el-select>
				</el-form-item>
				<el-form-item v-else class="input" label="知识类型" prop="zhishileixing" >
					<el-input v-model="ruleForm.zhishileixing"
						placeholder="知识类型" readonly></el-input>
				</el-form-item>
				<el-form-item class="upload" v-if="type!='info' && !ro.fengmian" label="封面" prop="fengmian" >
					<file-upload
						tip="点击上传封面"
						action="file/upload"
						:limit="3"
						:disabled="ro.fengmian"
						:multiple="true"
						:fileUrls="ruleForm.fengmian?ruleForm.fengmian:''"
						@change="fengmianUploadChange"
					></file-upload>
				</el-form-item>
				<el-form-item class="upload" v-else-if="ruleForm.fengmian" label="封面" prop="fengmian" >
					<img v-if="ruleForm.fengmian.substring(0,4)=='http'&&ruleForm.fengmian.split(',w').length>1" class="upload-img" style="margin-right:20px;" v-bind:key="index" :src="ruleForm.fengmian" width="100" height="100" @click="imgPreView(ruleForm.tupian)">
					<img v-else-if="ruleForm.fengmian.substring(0,4)=='http'" class="upload-img" style="margin-right:20px;" v-bind:key="index" :src="ruleForm.fengmian.split(',')[0]" width="100" height="100" @click="imgPreView(ruleForm.tupian.split(',')[0])">
					<img v-else class="upload-img" style="margin-right:20px;" v-bind:key="index" v-for="(item,index) in ruleForm.fengmian.split(',')" :src="$base.url+item" width="100" height="100" @click="imgPreView($base.url+item)">
				</el-form-item>
				<el-form-item class="input" v-if="type!='info'"  label="教师账号" prop="jiaoshizhanghao" >
					<el-input v-model="ruleForm.jiaoshizhanghao" placeholder="教师账号" clearable  :readonly="ro.jiaoshizhanghao"></el-input>
				</el-form-item>
				<el-form-item v-else class="input" label="教师账号" prop="jiaoshizhanghao" >
					<el-input v-model="ruleForm.jiaoshizhanghao" placeholder="教师账号" readonly></el-input>
				</el-form-item>
				<el-form-item class="input" v-if="type!='info'"  label="教师姓名" prop="jiaoshixingming" >
					<el-input v-model="ruleForm.jiaoshixingming" placeholder="教师姓名" clearable  :readonly="ro.jiaoshixingming"></el-input>
				</el-form-item>
				<el-form-item v-else class="input" label="教师姓名" prop="jiaoshixingming" >
					<el-input v-model="ruleForm.jiaoshixingming" placeholder="教师姓名" readonly></el-input>
				</el-form-item>
				<el-form-item class="fileupload" v-if="type!='info'&& !ro.caozuoshipin" label="操作视频" prop="caozuoshipin" >
					<file-upload
						tip="点击上传操作视频"
						action="file/upload"
						:limit="1"
						:type="2"
						:multiple="true"
						:disabled="ro.caozuoshipin"
						:fileUrls="ruleForm.caozuoshipin?ruleForm.caozuoshipin:''"
						@change="caozuoshipinUploadChange"
					></file-upload>
				</el-form-item> 
				<el-form-item v-else-if="ruleForm.caozuoshipin" label="操作视频" prop="caozuoshipin" >
					<el-button class="viewBtn" type="text" size="small" @click="download($base.url+ruleForm.caozuoshipin)">
						<span class="icon iconfont icon-chakan2"></span>
						预览
					</el-button>
				</el-form-item>
				<el-form-item v-else-if="!ruleForm.caozuoshipin" label="操作视频" prop="caozuoshipin" >
					<el-button class="unBtn" type="text" size="small">
						<span class="icon iconfont icon-jubao"></span>
						暂无
					</el-button>
				</el-form-item>
			</template>
			<el-form-item class="textarea" v-if="type!='info'" label="知识点要求" prop="zhishidianyaoqiu" >
				<el-input
					style="min-width: 200px; max-width: 600px;"
					type="textarea"
					:rows="8"
					placeholder="知识点要求"
					v-model="ruleForm.zhishidianyaoqiu" >
				</el-input>
			</el-form-item>
			<el-form-item v-else-if="ruleForm.zhishidianyaoqiu" label="知识点要求" prop="zhishidianyaoqiu"  class="textBox">
				<span class="text">{{ruleForm.zhishidianyaoqiu}}</span>
			</el-form-item>
			<el-form-item class="textarea" v-if="type!='info'" label="注意事项" prop="zhuyishixiang" >
				<el-input
					style="min-width: 200px; max-width: 600px;"
					type="textarea"
					:rows="8"
					placeholder="注意事项"
					v-model="ruleForm.zhuyishixiang" >
				</el-input>
			</el-form-item>
			<el-form-item v-else-if="ruleForm.zhuyishixiang" label="注意事项" prop="zhuyishixiang"  class="textBox">
				<span class="text">{{ruleForm.zhuyishixiang}}</span>
			</el-form-item>
			<el-form-item v-if="type!='info'" class="editorBox" label="详情" prop="xiangqing" >
				<editor 
					style="min-width: 200px; max-width: 600px;"
					v-model="ruleForm.xiangqing" 
					class="editor"
					myQuillEditor="xiangqing"
					action="file/upload">
				</editor>
			</el-form-item>
			<el-form-item v-else-if="ruleForm.xiangqing" label="详情" prop="xiangqing"  class="textBox">
				<span class="text ql-snow ql-editor" v-html="ruleForm.xiangqing"></span>
			</el-form-item>
			<el-form-item class="btn">
				<el-button class="btn3"  v-if="type!='info'" type="success" @click="onSubmit">
					<span class="icon iconfont icon-queren15"></span>
					提交
				</el-button>
				<el-button class="btn4" v-if="type!='info'" type="success" @click="back()">
					<span class="icon iconfont icon-guanbi2"></span>
					取消
				</el-button>
				<el-button class="btn5" v-if="type=='info'" type="success" @click="back()">
					<span class="icon iconfont icon-fanhui13"></span>
					返回
				</el-button>
			</el-form-item>
		</el-form>
    

	</div>
</template>
<script>
	import { 
		isIntNumer,
	} from "@/utils/validate";
	export default {
		data() {
			var validateIntNumber = (rule, value, callback) => {
				if(!value){
					callback();
				} else if (!isIntNumer(value)) {
					callback(new Error("请输入整数"));
				} else {
					callback();
				}
			};
			return {
				id: '',
				type: '',
			
			
				ro:{
					zhishibiaoti : false,
					zhishileixing : false,
					fengmian : false,
					zhishidianyaoqiu : false,
					zhuyishixiang : false,
					xiangqing : false,
					jiaoshizhanghao : false,
					jiaoshixingming : false,
					caozuoshipin : false,
					thumbsupnum : false,
					crazilynum : false,
					clicknum : false,
					discussnum : false,
					storeupnum : false,
				},
			
				ruleForm: {
					zhishibiaoti: '',
					zhishileixing: '',
					fengmian: '',
					zhishidianyaoqiu: '',
					zhuyishixiang: '',
					xiangqing: '',
					jiaoshizhanghao: '',
					jiaoshixingming: '',
					caozuoshipin: '',
					thumbsupnum: Number('0'),
					crazilynum: Number('0'),
					clicknum: Number('0'),
					discussnum: Number('0'),
					storeupnum: Number('0'),
				},
				zhishileixingOptions: [],

				rules: {
					zhishibiaoti: [
					],
					zhishileixing: [
					],
					fengmian: [
					],
					zhishidianyaoqiu: [
					],
					zhuyishixiang: [
					],
					xiangqing: [
					],
					jiaoshizhanghao: [
					],
					jiaoshixingming: [
					],
					caozuoshipin: [
					],
					thumbsupnum: [
						{ validator: validateIntNumber, trigger: 'blur' },
					],
					crazilynum: [
						{ validator: validateIntNumber, trigger: 'blur' },
					],
					clicknum: [
						{ validator: validateIntNumber, trigger: 'blur' },
					],
					discussnum: [
						{ validator: validateIntNumber, trigger: 'blur' },
					],
					storeupnum: [
						{ validator: validateIntNumber, trigger: 'blur' },
					],
				},
			};
		},
		props: ["parent"],
		computed: {
			sessionForm() {
				return JSON.parse(this.$storage.getObj('userForm'))
			},
			sessionTable() {
				return this.$storage.get('sessionTable')
			},



		},
		components: {
		},
		created() {
		},
		methods: {
			imgPreView(url){
				this.$parent.imgPreView(url)
			},
			// 下载
			download(file){
				window.open(`${file}`)
			},
			// 初始化
			init(id,type ) {
				if (id) {
					this.id = id;
					this.type = type;
				}
				if(this.type=='info'||this.type=='else'||this.type=='msg'){
					this.info(id);
				}else if(this.type=='logistics'){
					for(let x in this.ro) {
						this.ro[x] = true
					}
					this.logistics=false;
					this.info(id);
				}else if(this.type=='cross'){
					var obj = this.$storage.getObj('crossObj');
					for (var o in obj){
						if(o=='zhishibiaoti'){
							this.ruleForm.zhishibiaoti = obj[o];
							this.ro.zhishibiaoti = true;
							continue;
						}
						if(o=='zhishileixing'){
							this.ruleForm.zhishileixing = obj[o];
							this.ro.zhishileixing = true;
							continue;
						}
						if(o=='fengmian'){
							this.ruleForm.fengmian = obj[o];
							this.ro.fengmian = true;
							continue;
						}
						if(o=='zhishidianyaoqiu'){
							this.ruleForm.zhishidianyaoqiu = obj[o];
							this.ro.zhishidianyaoqiu = true;
							continue;
						}
						if(o=='zhuyishixiang'){
							this.ruleForm.zhuyishixiang = obj[o];
							this.ro.zhuyishixiang = true;
							continue;
						}
						if(o=='xiangqing'){
							this.ruleForm.xiangqing = obj[o];
							this.ro.xiangqing = true;
							continue;
						}
						if(o=='jiaoshizhanghao'){
							this.ruleForm.jiaoshizhanghao = obj[o];
							this.ro.jiaoshizhanghao = true;
							continue;
						}
						if(o=='jiaoshixingming'){
							this.ruleForm.jiaoshixingming = obj[o];
							this.ro.jiaoshixingming = true;
							continue;
						}
						if(o=='caozuoshipin'){
							this.ruleForm.caozuoshipin = obj[o];
							this.ro.caozuoshipin = true;
							continue;
						}
						if(o=='thumbsupnum'){
							this.ruleForm.thumbsupnum = obj[o];
							this.ro.thumbsupnum = true;
							continue;
						}
						if(o=='crazilynum'){
							this.ruleForm.crazilynum = obj[o];
							this.ro.crazilynum = true;
							continue;
						}
						if(o=='clicknum'){
							this.ruleForm.clicknum = obj[o];
							this.ro.clicknum = true;
							continue;
						}
						if(o=='discussnum'){
							this.ruleForm.discussnum = obj[o];
							this.ro.discussnum = true;
							continue;
						}
						if(o=='storeupnum'){
							this.ruleForm.storeupnum = obj[o];
							this.ro.storeupnum = true;
							continue;
						}
					}
				}

				// 获取用户信息
				this.$http({
					url: `${this.sessionTable}/session`,
					method: "get"
				}).then(({ data }) => {
					if (data && data.code === 0) {
						var json = data.data;
						if(((json.jiaoshizhanghao!=''&&json.jiaoshizhanghao) || json.jiaoshizhanghao==0) && this.sessionTable!="users"){
							this.ruleForm.jiaoshizhanghao = json.jiaoshizhanghao
							this.ro.jiaoshizhanghao = true;
						}
						if(((json.jiaoshixingming!=''&&json.jiaoshixingming) || json.jiaoshixingming==0) && this.sessionTable!="users"){
							this.ruleForm.jiaoshixingming = json.jiaoshixingming
							this.ro.jiaoshixingming = true;
						}
					} else {
						this.$message.error(data.msg);
					}
				});
				this.$http({
					url: `option/zhishileixing/zhishileixing`,
					method: "get",
				}).then(({ data }) => {
					if (data && data.code === 0) {
						this.zhishileixingOptions = data.data;
					} else {
						this.$message.error(data.msg);
					}
				});
			
			},
			// 多级联动参数

			async info(id) {
				await this.$http({
					url: `shiyanzhidao/info/${id}`,
					method: "get"
				}).then(({ data }) => {
					if (data && data.code === 0) {
						this.ruleForm = data.data;
						//解决前台上传图片后台不显示的问题
						let reg=new RegExp('../../../upload','g')//g代表全部
						this.ruleForm.xiangqing = this.ruleForm.xiangqing.replace(reg,'../../../shiyanshi88x6c3gh/upload');
					} else {
						this.$message.error(data.msg);
					}
				});
			},

			// 提交
			async onSubmit() {
					if(this.ruleForm.fengmian!=null) {
						this.ruleForm.fengmian = this.ruleForm.fengmian.replace(new RegExp(this.$base.url,"g"),"");
					}
					if(this.ruleForm.caozuoshipin!=null) {
						this.ruleForm.caozuoshipin = this.ruleForm.caozuoshipin.replace(new RegExp(this.$base.url,"g"),"");
					}
					var objcross = this.$storage.getObj('crossObj');
					if(!this.ruleForm.id) {
						delete this.ruleForm.userid
					}
					await this.$refs["ruleForm"].validate(async valid => {
						if (valid) {
							if(this.type=='cross'){
								var statusColumnName = this.$storage.get('statusColumnName');
								var statusColumnValue = this.$storage.get('statusColumnValue');
								if(statusColumnName!='') {
									var obj = this.$storage.getObj('crossObj');
									if(statusColumnName && !statusColumnName.startsWith("[")) {
										for (var o in obj){
											if(o==statusColumnName){
												obj[o] = statusColumnValue;
											}
										}
										var table = this.$storage.get('crossTable');
										await this.$http({
											url: `${table}/update`,
											method: "post",
											data: obj
										}).then(({ data }) => {});
									}
								}
							}
							await this.$http({
								url: `shiyanzhidao/${!this.ruleForm.id ? "save" : "update"}`,
								method: "post",
								data: this.ruleForm
							}).then(async ({ data }) => {
								if (data && data.code === 0) {
									this.$message({
										message: "操作成功",
										type: "success",
										duration: 1500,
										onClose: () => {
											this.parent.showFlag = true;
											this.parent.addOrUpdateFlag = false;
											this.parent.shiyanzhidaoCrossAddOrUpdateFlag = false;
											this.parent.search();
										}
									});
								} else {
									this.$message.error(data.msg);
								}
							});
						}
					});
			},
			// 获取uuid
			getUUID () {
				return new Date().getTime();
			},
			// 返回
			back() {
				this.parent.showFlag = true;
				this.parent.addOrUpdateFlag = false;
				this.parent.shiyanzhidaoCrossAddOrUpdateFlag = false;
			},
			fengmianUploadChange(fileUrls) {
				this.ruleForm.fengmian = fileUrls;
			},
			caozuoshipinUploadChange(fileUrls) {
				this.ruleForm.caozuoshipin = fileUrls;
			},
		}
	};
</script>
