					this.chartDialogShow2()
				}
				if(this.isAuth('shebeiyuyue','设备预约次数')) {
					this.chartDialogShow3()
				}
				if(this.isAuth('shebeiyuyue','设备归还占比')) {
					this.chartDialogShow4()
				}
			},
			queryChange(arr){
