					params['shebeifenlei'] = '%' + this.searchForm.shebeifenlei + '%'
				}
				if(this.searchForm.xinghao!='' && this.searchForm.xinghao!=undefined){
					params['xinghao'] = '%' + this.searchForm.xinghao + '%'
				}
				if(this.searchForm.sfsh!='' && this.searchForm.sfsh!=undefined){
					params['sfsh'] = this.searchForm.sfsh
				}
				let user = JSON.parse(this.$storage.getObj('userForm'))
				this.$http({
					url: "shebeiyuyue/page",
					method: "get",
					params: params
				}).then(({ data }) => {
					if (data && data.code === 0) {
						this.dataList = data.data.list;
						this.totalPage = data.data.total;
					} else {
						this.dataList = [];
						this.totalPage = 0;
					}
					this.dataListLoading = false;
				});
			},
			// 每页数
			sizeChangeHandle(val) {
				this.pageSize = val;
				this.pageIndex = 1;
				this.getDataList();
			},
			// 当前页
			currentChangeHandle(val) {
				this.pageIndex = val;
				this.getDataList();
			},
			// 多选
			selectionChangeHandler(val) {
				this.dataListSelections = val;
			},
			// 添加/修改
			addOrUpdateHandler(id,type) {
				this.showFlag = false;
				this.addOrUpdateFlag = true;
				this.crossAddOrUpdateFlag = false;
				if(type!='info'&&type!='msg'){
					type = 'else';
				}
				this.$nextTick(() => {
					this.$refs.addOrUpdate.init(id,type );
				});
			},
			async getAllList() {
				return new Promise(async(resolve, reject) => {
					await this.$http({
						url: 'shebeiyuyue/page',
						method: 'get',
						params: {
							limit: 10000
						}
					}).then(rs => {
						resolve(rs.data.data.list)
					})
				})
			
			},
			//批量审核窗口
			shBatchDialog(){
				for(let x in this.dataListSelections){
					if(this.dataListSelections[x].sfsh&&this.dataListSelections[x].sfsh!='待审核'){
						this.$message.error('存在已审核数据，不能继续操作');
						this.batchIds = []
						return false
					}
					this.batchIds.push(this.dataListSelections[x].id)
				}
				this.shList = this.dataListSelections
				this.sfshBatchVisiable = true
			},
			//批量审核
			shBatchHandler(){
				this.$refs["shBatchForm"].validate(valid => {
					if(valid){
						this.$confirm(`是否${this.batchIds.length>1?'一键审核':'审核'}选中数据?`, "提示", {
							confirmButtonText: "确定",
							cancelButtonText: "取消",
							type: "warning"
						}).then(async() => {
							let changeType = true
							let errMsg = ''
							if(this.shBatchForm.sfsh=='是') {
								for(let x in this.shList){
									await this.$http.post('updateColumn/shiyanshebei/2',{
										csuUpdateColumn: 'shuliang',
										csuUpdateColumnValue: '-' + this.shList[x].shuliang,
										csuConditionColumn: 'shebeibianhao',
										csuConditionColumnValue: this.shList[x].shebeibianhao
									}).then(rs=>{
										if(rs.data.code!=0) {
											changeType = false
											errMsg = '库存不足'
										}
									},err=>{
										changeType = false
										errMsg = '库存不足'
									})
								}
							}
							if(!changeType) {
								this.$message.error(errMsg);
								return false
							}
							this.$http({
								url: "shebeiyuyue/shBatch?sfsh="+this.shBatchForm.sfsh+"&shhf="+this.shBatchForm.shhf,
								method: "post",
								data: this.batchIds
							}).then(async ({ data }) => {
								if (data && data.code === 0) {
									if(this.shBatchForm.sfsh!='待审核'){
										for(let x in this.shList){
											await this.$http.get('xuesheng/query',{params: {
												xueshengxuehao: this.shList[x].xueshengxuehao
											}}).then(async rs=>{
												if(rs.data.data.email) {
													await this.$http.get('xuesheng/sendemail/content',{params: {
														email: rs.data.data.email,
														title: '设备预约',
														content: `你提交的“设备预约”申请${this.shBatchForm.sfsh=='是'?'审核通过':'审核不通过'}`,
													}}).then(rs=>{})
												}
												let param = {
													userid: rs.data.data.id,
													title: '设备预约',
													type: '个人',
													brief: this.shBatchForm.sfsh=='是'?'审核通过':'审核不通过',
													content: `你提交的“设备预约”申请${this.shBatchForm.sfsh=='是'?'审核通过':'审核不通过'}`,
													remindtime: this.getCurDateTime(),
												}
												await this.$http.post('popupremind/add',param).then(rs=>{})
											})
										}
									}
									this.$message({
										message: "操作成功",
										type: "success",
										duration: 1500,
										onClose: () => {
											this.getDataList();
											this.sfshBatchVisiable = false
											this.batchIds = []
										}
									});
								} else {
									this.$message.error(data.msg);
								}
							});
						});
					}
				})
			},
			// 删除
			async deleteHandler(id ) {
				var ids = id? [Number(id)]: this.dataListSelections.map(item => {
					return Number(item.id);
				});
				await this.$confirm(`确定进行[${id ? "删除" : "批量删除"}]操作?`, "提示", {
					confirmButtonText: "确定",
					cancelButtonText: "取消",
					type: "warning"
				}).then(async () => {
					await this.$http({
						url: "shebeiyuyue/delete",
						method: "post",
						data: ids
					}).then(async ({ data }) => {
						if (data && data.code === 0) {
							this.$message({
								message: "操作成功",
								type: "success",
								duration: 1500,
								onClose: () => {
									this.search();
								}
							});
			
						} else {
							this.$message.error(data.msg);
						}
					});
				});
			},


		}

	};
